import React from 'react';
import { useSearchParams } from 'react-router-dom';
import { VoucherRegistryTab } from './VoucherRegistryTab';
import { VoucherCodeFormatTab } from './VoucherCodeFormatTab';
import { ProcessingLevelsTab } from './ProcessingLevelsTab';
import styles from '../../../styles/erpPage.module.css';

const TEST_ID = 'system-voucher-setup';

const TABS = [
  { id: 'registry', label: 'Đăng ký chứng từ', icon: 'fa-file-invoice' },
  { id: 'format', label: 'Định dạng mã', icon: 'fa-barcode' },
  { id: 'levels', label: 'Mức xử lý', icon: 'fa-layer-group' },
] as const;

type TabId = (typeof TABS)[number]['id'];

const isTabId = (value: string | null): value is TabId =>
  TABS.some(tab => tab.id === value);

const VoucherSetupPage: React.FC = () => {
  const [searchParams, setSearchParams] = useSearchParams();
  const tabParam = searchParams.get('tab');
  const activeTab: TabId = isTabId(tabParam) ? tabParam : 'registry';

  const setActiveTab = (tabId: TabId) => {
    setSearchParams(prev => {
      const next = new URLSearchParams(prev);
      next.set('tab', tabId);
      return next;
    }, { replace: true });
  };

  return (
    <div className={styles.page} data-testid={TEST_ID}>
      <div className={styles.pageHeader}>
        <div className={styles.titleBlock}>
          <h1 className={styles.title}>
            <i className="fas fa-file-invoice" /> Thiết lập chứng từ
          </h1>
          <p className={styles.subtitle}>
            Đăng ký loại chứng từ, định dạng mã và tên các mức xử lý/phê duyệt.
          </p>
        </div>
      </div>

      <div className={styles.tabs} data-testid={`${TEST_ID}-tabs`}>
        {TABS.map(tab => (
          <button
            key={tab.id}
            type="button"
            className={`${styles.tab}${activeTab === tab.id ? ` ${styles.tabActive}` : ''}`}
            onClick={() => setActiveTab(tab.id)}
            data-testid={`${TEST_ID}-tab-${tab.id}`}
          >
            <i className={`fas ${tab.icon}`} style={{ marginRight: 6 }} />
            {tab.label}
          </button>
        ))}
      </div>

      {activeTab === 'registry' && <VoucherRegistryTab />}
      {activeTab === 'format' && <VoucherCodeFormatTab />}
      {activeTab === 'levels' && <ProcessingLevelsTab />}
    </div>
  );
};

export default VoucherSetupPage;
