export interface VoucherCodeFormatDto {
  id: string;
  codeType: string;
  prefix: string;
  description: string;
  format: string;
  minSequence: number;
  maxSequence: number;
  seqPadding: number;
  resetDaily: boolean;
  isActive: boolean;
  exampleCode: string;
}

export interface UpdateVoucherCodeFormatDto {
  format: string;
  seqPadding: number;
  minSequence: number;
  maxSequence: number;
}

export const FORMAT_PATTERN_DAILY = 'PREFIX-YYYYMMDD-NNNN';
export const FORMAT_PATTERN_SEQUENTIAL = 'PREFIX-NNNN';

export const SEQ_PADDING_MIN = 1;
export const SEQ_PADDING_MAX = 10;

export const VOUCHER_CODE_FORMAT_OPTIONS = [
  { value: FORMAT_PATTERN_DAILY, label: 'PREFIX-YYYYMMDD-NNNN (vd. PC-20260521-0001)' },
  { value: FORMAT_PATTERN_SEQUENTIAL, label: 'PREFIX-NNNN (không reset theo ngày)' },
] as const;

/** Preview mã — khớp BE `IdCodeFormatHelper.BuildCode`. */
export function buildVoucherCodePreview(
  prefix: string,
  format: string,
  seqPadding: number,
  minSequence = 1,
): string {
  const pad = Math.min(10, Math.max(1, seqPadding || 4));
  const seq = String(minSequence).padStart(pad, '0');
  const resetDaily =
    format === FORMAT_PATTERN_DAILY
    || format.toUpperCase().includes('YYYYMMDD');

  if (resetDaily) {
    const now = new Date();
    const y = now.getFullYear();
    const m = String(now.getMonth() + 1).padStart(2, '0');
    const d = String(now.getDate()).padStart(2, '0');
    return `${prefix}-${y}${m}${d}-${seq}`;
  }
  return `${prefix}-${seq}`;
}
