import type { LedgerKind } from './voucherRegistryModels';

export interface ProcessingLevelDto {
  level: number;
  postCode?: string;
  name: string;
  nameEn?: string;
}

export interface UpdateProcessingLevelItemDto {
  level: number;
  postCode?: string;
  name: string;
  nameEn?: string;
}

export interface UpdateProcessingLevelsDto {
  levels: UpdateProcessingLevelItemDto[];
}

export const DEFAULT_LEVEL_NAMES: Record<LedgerKind, Partial<Record<number, string>>> = {
  Accounting: {
    1: 'Nhập liệu',
    3: 'Lập chứng từ',
    9: 'Hoạch toán sổ cái',
  },
  Warehouse: {
    1: 'Nhập liệu',
    3: 'Lập chứng từ',
    9: 'Ghi sổ',
  },
};

export function mergeProcessingLevels(
  ledgerKind: LedgerKind,
  fromApi: ProcessingLevelDto[],
): ProcessingLevelDto[] {
  const byLevel = new Map(fromApi.map(row => [row.level, row]));
  return Array.from({ length: 9 }, (_, i) => {
    const level = i + 1;
    const existing = byLevel.get(level);
    if (existing) return existing;
    return {
      level,
      postCode: '',
      name: DEFAULT_LEVEL_NAMES[ledgerKind][level] ?? '',
      nameEn: '',
    };
  });
}
