/** UI form shape for SystemSettingsPage. */
export interface SystemSettingsFormDto {
  companyName?: string;
  taxCode?: string;
  companyAddress?: string;
  phone?: string;
  email?: string;
  fiscalYearStartMonth?: number;
  defaultCurrency?: string;
  decimalPlaces?: number;
  useMultiCurrency?: boolean;
  cutoffDate?: string;
}

/** Wire DTO from `SystemController` / `SystemSettingsService`. */
export interface SystemSettingsApiDto {
  companyName?: string | null;
  taxCode?: string | null;
  companyAddress?: string | null;
  phone?: string | null;
  email?: string | null;
  fiscalYearStartMonth?: string;
  defaultCurrencyCode?: string;
  decimalPlaces?: number;
  useMultiCurrency?: boolean;
  cutoffDate?: string | null;
  inventoryValuationMethod?: string;
  requirePurchaseApproval?: boolean;
  approvalThreshold?: number;
}

export function mapSystemSettingsFromApi(dto: SystemSettingsApiDto): SystemSettingsFormDto {
  const month = Number(dto.fiscalYearStartMonth ?? 1);
  return {
    companyName: dto.companyName ?? undefined,
    taxCode: dto.taxCode ?? undefined,
    companyAddress: dto.companyAddress ?? undefined,
    phone: dto.phone ?? undefined,
    email: dto.email ?? undefined,
    fiscalYearStartMonth: Number.isFinite(month) && month >= 1 && month <= 12 ? month : 1,
    defaultCurrency: dto.defaultCurrencyCode ?? 'VND',
    decimalPlaces: dto.decimalPlaces ?? 0,
    useMultiCurrency: dto.useMultiCurrency ?? false,
    cutoffDate: dto.cutoffDate?.slice(0, 10) || undefined,
  };
}

export function mapSystemSettingsToApi(form: SystemSettingsFormDto): SystemSettingsApiDto {
  return {
    companyName: form.companyName ?? '',
    taxCode: form.taxCode ?? '',
    companyAddress: form.companyAddress ?? '',
    phone: form.phone ?? '',
    email: form.email ?? '',
    fiscalYearStartMonth: String(form.fiscalYearStartMonth ?? 1),
    defaultCurrencyCode: form.defaultCurrency ?? 'VND',
    decimalPlaces: form.decimalPlaces ?? 0,
    useMultiCurrency: form.useMultiCurrency ?? false,
    cutoffDate: form.cutoffDate || null,
    inventoryValuationMethod: 'FIFO',
    requirePurchaseApproval: false,
    approvalThreshold: 0,
  };
}
