import React, { useState } from 'react';
import { Button, Input, dispatchAppToast } from '@linm-soft-org/linm-web-common-components';
import { useAppDispatch } from '../../../store/hooks';
import { systemService } from '../../../services/system/systemService';
import type { LedgerKind } from '../../../services/system/voucherRegistryModels';
import { LEDGER_KIND_OPTIONS } from '../../../services/system/voucherRegistryModels';
import type { ProcessingLevelDto } from '../../../services/system/processingLevelModels';
import { mergeProcessingLevels } from '../../../services/system/processingLevelModels';
import { ListSearchRefreshButtons } from '../../../components/list/ListSearchRefreshButtons';
import styles from '../../../styles/erpPage.module.css';

const TEST_ID = 'system-voucher-setup-levels';

export const ProcessingLevelsTab: React.FC = () => {
  const dispatch = useAppDispatch();
  const [ledgerKind, setLedgerKind] = useState<LedgerKind>('Accounting');
  const [rows, setRows] = useState<ProcessingLevelDto[]>(() => mergeProcessingLevels('Accounting', []));
  const [loading, setLoading] = useState(false);
  const [saving, setSaving] = useState(false);
  const [dirty, setDirty] = useState(false);
  const [reloadKey, setReloadKey] = useState(0);

  const refresh = () => setReloadKey(k => k + 1);

  React.useEffect(() => {
    let cancelled = false;
    setLoading(true);
    setDirty(false);
    const t = setTimeout(() => {
      systemService.getProcessingLevels(ledgerKind)
        .then(data => {
          if (!cancelled) setRows(mergeProcessingLevels(ledgerKind, data));
        })
        .catch(err => {
          if (!cancelled) {
            dispatchAppToast(dispatch, {
              message: err instanceof Error ? err.message : 'Lỗi tải mức xử lý',
              type: 'error',
            });
            setRows(mergeProcessingLevels(ledgerKind, []));
          }
        })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [ledgerKind, reloadKey, dispatch]);

  const switchLedgerKind = (kind: LedgerKind) => {
    if (kind === ledgerKind) return;
    setLedgerKind(kind);
  };

  const updateRow = (level: number, patch: Partial<ProcessingLevelDto>) => {
    setRows(prev => prev.map(r => (r.level === level ? { ...r, ...patch } : r)));
    setDirty(true);
  };

  const handleSave = async () => {
    const payload = rows
      .filter(r => r.name.trim())
      .map(r => ({
        level: r.level,
        postCode: r.postCode?.trim() || undefined,
        name: r.name.trim(),
        nameEn: r.nameEn?.trim() || undefined,
      }));

    if (payload.length === 0) {
      dispatchAppToast(dispatch, { message: 'Nhập tên ít nhất một mức xử lý', type: 'error' });
      return;
    }

    setSaving(true);
    try {
      const saved = await systemService.updateProcessingLevels(ledgerKind, { levels: payload });
      setRows(mergeProcessingLevels(ledgerKind, saved));
      setDirty(false);
      dispatchAppToast(dispatch, { message: 'Lưu mức xử lý thành công', type: 'success' });
    } catch (err: unknown) {
      dispatchAppToast(dispatch, {
        message: err instanceof Error ? err.message : 'Lưu thất bại',
        type: 'error',
      });
    } finally {
      setSaving(false);
    }
  };

  return (
    <>
      <p className={styles.subtitle} style={{ marginBottom: 12 }}>
        Khai báo tên mức 1–9 theo loại sổ. Mức 9 trên list/form ERP: Accounting → Hoạch toán sổ cái; Warehouse → Ghi sổ.
      </p>

      <div className={styles.tabs} data-testid={`${TEST_ID}-ledger-tabs`}>
        {LEDGER_KIND_OPTIONS.map(opt => (
          <button
            key={opt.value}
            type="button"
            className={`${styles.tab}${ledgerKind === opt.value ? ` ${styles.tabActive}` : ''}`}
            onClick={() => switchLedgerKind(opt.value as LedgerKind)}
            data-testid={`${TEST_ID}-ledger-${opt.value}`}
          >
            {opt.label}
          </button>
        ))}
      </div>

      <div className={styles.filtersBar} data-testid={`${TEST_ID}-toolbar`}>
        <ListSearchRefreshButtons testIdPrefix={TEST_ID} onSearch={refresh} onRefresh={refresh} showSearch={false} />
        <Button
          variant="primary"
          onClick={handleSave}
          disabled={saving || !dirty}
          data-testid={`${TEST_ID}-save-btn`}
        >
          {saving ? 'Đang lưu...' : 'Lưu mức xử lý'}
        </Button>
      </div>

      <div className={styles.tableCard}>
        {loading ? (
          <div className={styles.loading}><i className="fas fa-spinner fa-spin" /> Đang tải...</div>
        ) : (
          <div className={styles.tableWrapper}>
            <table className={styles.table}>
              <thead>
                <tr>
                  <th style={{ width: 72 }}>Mức</th>
                  <th style={{ width: 120 }}>Mã post</th>
                  <th>Tên hiển thị</th>
                  <th>Tên tiếng Anh</th>
                </tr>
              </thead>
              <tbody>
                {rows.map(r => (
                  <tr key={r.level}>
                    <td><strong>{r.level}</strong></td>
                    <td>
                      <Input
                        value={r.postCode ?? ''}
                        onChange={e => updateRow(r.level, { postCode: e.target.value })}
                        data-testid={`${TEST_ID}-row-${r.level}-postCode`}
                      />
                    </td>
                    <td>
                      <Input
                        value={r.name}
                        onChange={e => updateRow(r.level, { name: e.target.value })}
                        placeholder={`Mức ${r.level}`}
                        data-testid={`${TEST_ID}-row-${r.level}-name`}
                      />
                    </td>
                    <td>
                      <Input
                        value={r.nameEn ?? ''}
                        onChange={e => updateRow(r.level, { nameEn: e.target.value })}
                        data-testid={`${TEST_ID}-row-${r.level}-nameEn`}
                      />
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </>
  );
};

export default ProcessingLevelsTab;
